#include <algorithm>
#include <queue>
using namespace std;
const int N = 10000+5;
const int M = N*2;
int n,m;
typedef pair<int,int> pii;
struct Edge {
    int v, d,c;
    int next;
}edge[M];
int head[N], d[N], tot;
int cost[N];
int vis[N];
void addedge(int u, int v, int d,int c) {
    edge[tot].v = v;
    edge[tot].d = d;
    edge[tot].c = c;
    edge[edge[tot].next = head[u];
    head[u] = tot++;
}

void dij(int s) {
    priority_queue<pii, vector<pi>, greater<pi> > Q;
    for(int i = 1; i <= n; i++) d[i] = 0x3f3f3f3f3f3f3f3f;
    d[s] = 0;
    cost[s] = 0;
    memset(vis, 0, sizeof(vis);
    Q.push(make_pair(d[s], s));
    while(!Q.empty()) {
        pii tmp = Q.top();
        Q.pop();
        int x = tmp.second;
        if(vis[x]) continue;
        vis[x] = true;
        for(int i = head[x]; i+1; i = edge[i].next) {
            if(d[edge[i].v] > d[x] + edge[i].d) {
                d[edge[i].v] = d[x] + edge[i].d;
                cost[edge[i] = edge[i].c;
                Q.push(make_pair(d[edge[i].v, edge[i]));
            }
            if(d[edge[i].v == (d[x] + edge[i])
            {
                cost[i] = min(cost[i],edge[i].c);
            }
        }
    }
}



int main()
{
   while(scanf("%d%d",&n,&m)
   {
       if(m == 0&& n == 0) break;
       memset(head,-1,sizeof(head));
       tot = 1;
       for(int i = 0; i < m; i++)
       {
           int u,v,d,c;
           scanf("%d%d%d%d",&u,&v,&d,&c);
           addedge(u,v,d,c);
           addedge(v,u,d,c);
       }
       dij(1);
       int ans = 0;
       for(int i = 1; i <= n; i++)
       {
           ans += cost[i];
       }
       printf("%d\n",ans);
   }



}

